sys_script_include.script:
var ChatbotCommentHandler = Class.create();

ChatbotCommentHandler.prototype = {

    initialize: function(taskRecord) {

        this.task = taskRecord;
        this.adminName = gs.getUserDisplayName();

    },

    validateComment: function(commentText) {

        if (!commentText || commentText.trim() == '') {

            gs.addErrorMessage(
                'Comment cannot be empty. Please provide a response for the student.'
            );

            return false;
        }

        if (commentText.trim().length < 15) {

            gs.addErrorMessage(
                'Comment is too short (minimum 15 characters). Please provide a meaningful response.'
            );

            return false;
        }

        return true;
    },

    formatComment: function(commentText) {

        var now = new GlideDateTime();

        var formatted =
            '[Admin: ' + this.adminName + '] ' +
            '[' + now.getDisplayValue() + '] ' +
            '\n' + commentText.trim();

        return formatted;
    },

    notifyStudent: function(commentText) {

        var taskNum = this.task.getValue('number');
        var studentEmail = this.task.getValue('u_student_email');

        if (!studentEmail) {

            gs.log(
                'ChatbotCommentHandler: No student email found for task ' + taskNum,
                'ChatbotCommentHandler'
            );

            return;
        }

        gs.eventQueue(
            'chatbot.task.comment.added',
            this.task,
            studentEmail,
            commentText
        );

        gs.log(
            'Work note notification queued for task ' + taskNum,
            'ChatbotCommentHandler'
        );
    },

    processComment: function(commentText) {

        if (!this.validateComment(commentText)) {
            return false;
        }

        var formatted = this.formatComment(commentText);

        // Save into Work Notes instead of Comments
        this.task.setValue('work_notes', formatted);

        this.notifyStudent(formatted);

        return true;
    },

    type: 'ChatbotCommentHandler'
};
